import React from "react";
import { FaHome, FaUserFriends, FaBell, FaCog, FaSignOutAlt } from "react-icons/fa";

const Sidebar = ({ onNavigate }) => {
  return (
    <div className="fixed top-[160px] left-0 flex flex-col items-center bg-[#88BCF8] w-[72px] py-[20px] px-[10px] gap-[30px] rounded-r-2xl shadow-md z-30">
      <FaHome
        size={26}
        className="cursor-pointer hover:scale-110 transition-transform"
        onClick={() => onNavigate("home")}
      />
      <FaUserFriends
        size={26}
        className="cursor-pointer hover:scale-110 transition-transform"
        onClick={() => onNavigate("friends")}
      />
      <FaBell
        size={26}
        className="cursor-pointer hover:scale-110 transition-transform"
        onClick={() => onNavigate("notifications")}
      />
      <FaCog
        size={26}
        className="cursor-pointer hover:scale-110 transition-transform"
      />
      <FaSignOutAlt
        size={26}
        className="cursor-pointer hover:scale-110 transition-transform"
      />
    </div>
  );
};

export default Sidebar;
